#include<bits/stdc++.h>
using namespace std;
int a[3010],f[3010][3010],w[3010][3010];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    stable_sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        for(int j=i+1;j<=n;j++)
        {
            w[i][j]=w[i][j-1]+a[j]-a[(i+j)>>1];
        }
    }
    memset(f,0x3f,sizeof(f));
    f[0][0]=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=min(i,m);j++)
        {
            for(int k=max(j-1,i-500);k<i;k++)
            {
                if(f[i][j]>f[k][j-1]+w[k+1][i])
                {
                    f[i][j]=f[k][j-1]+w[k+1][i];
                }
            }
        }
    }
    printf("%d",f[n][m]);
    return 0;
}
